import { parseTsconfig } from 'get-tsconfig';
import { isFile } from './fs.js';
import { _syncGlob } from './glob.js';
import { dirname, isAbsolute, join, toAbsolute } from './path.js';
const hasGlobChar = (p) => p.includes('*') || p.includes('?');
